#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN=(1<<18)+5;
int f[MAXN],n,m,st[MAXN],dist[MAXN];
queue<int> q;
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	IOS
	cin>>m>>n;
	FOR(i,1,n)
	{
		string s;
		cin>>s;
		s=' '+s;
		int mask=0;
		FOR(j,1,m)
		{
			mask+=(s[j]-'G')*(1<<(j-1));
		}
		f[i]=mask;
		if(!st[mask])
		{
			st[mask]=1;
			q.push(mask);
			dist[mask]=0;
		}
	}
	wh(q.size())
	{
		int mask=q.front();
		q.pop();
		FOR(i,0,m-1)
		{
			int now=mask^(1<<i);
			if(!st[now])
			{
				st[now]=1;
				q.push(now);
				dist[now]=dist[mask]+1;
			}
		}
	}
	FOR(i,1,n)
	{
		int mask=f[i]^((1<<m)-1);
		cout<<m-dist[mask]<<'\n';	
	}
    return false;
}
